+auto parse_zero_one_bool(std::string_view value) -> MysqlResult<bool> {
+  if (value == "0") {
+    return false;
+  }
+  if (value == "1") {
+    return true;
+  }
+  return Err{mysql_error::protocol(
+    fmt::format("expected bool encoded as 0/1, got `{}`", value))};
+}
